    20→import edu.wpi.first.wpilibj2.command.SubsystemBase;
    21→import edu.wpi.first.wpilibj2.command.button.Trigger;
    22→import org.littletonrobotics.junction.Logger;
    23→import yams.mechanisms.config.ElevatorConfig;
    24→import yams.mechanisms.positional.Elevator;
    25→import yams.motorcontrollers.SmartMotorController;
    26→import yams.motorcontrollers.SmartMotorControllerConfig;
    27→import yams.motorcontrollers.SmartMotorControllerConfig.ControlMode;
    28→import yams.motorcontrollers.SmartMotorControllerConfig.MotorMode;
    29→import yams.motorcontrollers.local.SparkWrapper;
    30→
    31→public class ExtensorSubsystem extends SubsystemBase {
    32→
    33→  private static ExtensorSubsystem instance;
    34→
    35→  public static ExtensorSubsystem getInstance() {
    36→    if (instance == null) {
    37→      instance = new ExtensorSubsystem();
    38→    }
    39→    return instance;
    40→  }
    41→
    42→  private final ExtensorInputsAutoLogged extensorInputs;
    43→
    44→  private final SparkFlex extensorSparkFlex;
    45→
    46→  private final SmartMotorControllerConfig extensorMotorConfig;
    47→
    48→  private final SmartMotorController extensorMotor;
    49→
    50→  private final ElevatorConfig extensorConfig;
    51→
    52→  private final Elevator extensor;
    53→
    54→  private Distance setpoint = Meters.of(0);
    55→
    56→  private ExtensorSubsystem() {
    57→    this.extensorInputs = new ExtensorInputsAutoLogged();
    58→    this.extensorSparkFlex = new SparkFlex(ExtensorConstants.ID_MOTOR, MotorType.kBrushless);
    59→
    60→    this.extensorMotorConfig =
    61→        new SmartMotorControllerConfig(this)
    62→            .withMechanismCircumference(ExtensorConstants.MECHANISM_CIRCUNFERENCE)
    63→            .withClosedLoopRampRate(Milliseconds.of(10))
    64→            .withClosedLoopController(
    65→                0.5, 0, 0, ExtensorConstants.maxVel, ExtensorConstants.maxAccel)
    66→            .withSimClosedLoopController(
    67→                0.5, 0, 0, ExtensorConstants.maxVel, ExtensorConstants.maxAccel)
    68→            .withFeedforward(new SimpleMotorFeedforward(0.17, 0.2, 0))
    69→            .withSimFeedforward(new SimpleMotorFeedforward(0.17, 0.2, 0))
    70→            .withGearing(ExtensorConstants.gearing)
    71→            .withIdleMode(MotorMode.COAST)
    72→            .withStatorCurrentLimit(Amps.of(60))
    73→            .withMotorInverted(false)
    74→            .withControlMode(ControlMode.CLOSED_LOOP);
    75→
    76→    this.extensorMotor =
    77→        new SparkWrapper(extensorSparkFlex, ExtensorConstants.motor, extensorMotorConfig);
    78→
    79→    this.extensorConfig =
    80→        new ElevatorConfig(extensorMotor)
    81→            .withMass(ExtensorConstants.mass)
    82→            .withDrumRadius(ExtensorConstants.drumRadius)
    83→            .withSoftLimits(
    84→                ExtensorConstants.limits.MIN_EXTENSION, ExtensorConstants.limits.MAX_EXTENSION)
    85→            .withHardLimits(
    86→                ExtensorConstants.limits.MIN_EXTENSION, ExtensorConstants.limits.MAX_EXTENSION)
    87→            .withStartingHeight(Meters.of(0));
    88→
    89→    this.extensor = new Elevator(extensorConfig);
    90→  }
    91→
    92→  @Override
    93→  public void periodic() {
    94→    updateInputs();
    95→    Logger.processInputs("Subsystems/Extensor", extensorInputs);
    96→    extensor.updateTelemetry();
    97→    setpoint =
    98→        Meters.of(
    99→            this.extensorMotor.getMechanismPositionSetpoint().isEmpty()
   100→                ? 0
   101→                : extensorMotor.getMechanismPositionSetpoint().get().in(Rotations)
   102→                    * ExtensorConstants.MECHANISM_CIRCUNFERENCE.in(Meters));
   103→  }
   104→
   105→  @Override
   106→  public void simulationPeriodic() {
   107→    this.extensor.simIterate();
   108→  }
   109→
   110→  public void updateInputs() {
   111→    extensorInputs.extensorVoltage = this.extensorMotor.getVoltage();
   112→    extensorInputs.extensorCurrent = this.extensorMotor.getStatorCurrent();
   113→    extensorInputs.extensorPosition = this.extensorMotor.getMeasurementPosition();
   114→    extensorInputs.extensorVelocity = this.extensorMotor.getMeasurementVelocity();
   115→    extensorInputs.extensorSetpoint = this.setpoint;
   116→  }
   117→
   118→  public Command extend() {
   119→    return this.setLength(ExtensorConstants.setpoints.INTAKE_EXTENDED_POSITION);
   120→  }
   121→
   122→  public Command retract() {
   123→    return this.extensor.setHeight(ExtensorConstants.setpoints.INTAKE_HOMED_POSITION);
   124→  }
   125→
   126→  public Command disableExtensor() {
   127→    return this.runOnce(
   128→        () -> {
   129→          this.extensorMotor.stopClosedLoopController();
   130→        });
   131→  }
   132→
   133→  public Command springyMode() {
   134→    return this.runOnce(() -> extensorMotor.setVoltage(Voltage.ofBaseUnits(0, Volts)));
   135→  }
   136→
   137→  public Command enableExtensor() {
   138→    return this.runOnce(
   139→        () -> {
   140→          this.extensorMotor.startClosedLoopController();
   141→        });
   142→  }
   143→
   144→  /**
   145→   * Reset the encoder to the lowest position when the current threshhold is reached. Should be used
   146→   * when the Extensor position is unreliable, like startup. Threshhold is only detected if exceeded
   147→   * for 0.4 seconds, and the motor moves less than 2 degrees per second.
   148→   *
   149→   * @param threshhold The current threshhold held when the Extensor is at it's hard limit.
   150→   * @return
   151→   */
   152→  public Command homing(Current threshhold) {
   153→    Debouncer currentDebouncer =
   154→        new Debouncer(0.1); // Current threshold is only detected if exceeded for 0.4 seconds.
   155→    Voltage runVolts = Volts.of(2); // Volts required to run the mechanism to the limit.
   156→    Distance limitHit =
   157→        ExtensorConstants.setpoints.INTAKE_EXTENDED_POSITION; // Limit which gets hit.
   158→    AngularVelocity velocityThreshold =
   159→        DegreesPerSecond.of(
   160→            2); // The maximum amount of movement for the extensor to be considered "hitting the
   161→    // hard limit".
   162→    return Commands.startRun(
   163→            extensorMotor::stopClosedLoopController, // Stop the closed loop controller
   164→            () -> extensorMotor.setVoltage(runVolts)) // Set the voltage of the motor
   165→        .until(
   166→            () ->
   167→                currentDebouncer.calculate(
   168→                    extensorMotor.getStatorCurrent().gte(threshhold)
   169→                        && extensorMotor.getMechanismVelocity().abs(DegreesPerSecond)
   170→                            <= velocityThreshold.in(DegreesPerSecond)))
   171→        .finallyDo(
   172→            () -> {
   173→              extensorMotor.setEncoderPosition(limitHit);
   174→              extensorMotor.startClosedLoopController();
   175→            });
   176→  }
   177→
   178→  private Command setLength(Distance length) {
   179→    return this.extensor.runTo(length, ExtensorConstants.DEADBAND_IS_AT);
   180→  }
   181→
   182→  public Trigger isAtTargetHeight() {
   183→    return new Trigger(
   184→        () -> extensor.getHeight().isNear(setpoint, ExtensorConstants.DEADBAND_IS_AT));
   185→  }
   186→
   187→  public Trigger isAtTargetHeightCollect() {
   188→    return new Trigger(
   189→        () ->
   190→            extensor
   191→                .getHeight()
   192→                .isNear(
   193→                    ExtensorConstants.setpoints.INTAKE_EXTENDED_POSITION,
   194→                    ExtensorConstants.DEADBAND_IS_AT));
   195→  }
   196→}
