    28→    public static final Distance MIN_EXTENSION = Meters.of(0);
    29→  }
    30→
    31→  public static final Current SPRINGY_MODE_CURRENT_LIMIT = Amps.of(1);
    32→  public static final Current NORMAL_MODE_CURRENT_LIMIT = Amps.of(60);
    33→
    34→  public static final Voltage maxVolts = Volts.of(12);
    35→  public static final AngularVelocity maxVel = RotationsPerSecond.of(1000);
    36→  public static final AngularAcceleration maxAccel = RotationsPerSecondPerSecond.of(10000);
    37→  public static final DCMotor motor = DCMotor.getNeoVortex(1);
    38→  public static final Mass mass = Kilograms.of(5);
