    40→  public static final MechanismGearing gearing =
    41→      new MechanismGearing(GearBox.fromReductionStages(5.71));
    42→
    43→  public static final Distance MECHANISM_CIRCUNFERENCE =
    44→      Meters.of(Math.PI * 2 * drumRadius.in(Meters));
    45→
    46→  public static final MechanismPositionConfig robotToMechanism =
    47→      new MechanismPositionConfig()
    48→          .withMaxRobotHeight(Meters.of(1.5))
    49→          .withMaxRobotLength(Meters.of(0.75))
    50→          .withRelativePosition(new Translation3d(Meters.of(-0.25), Meters.of(0), Meters.of(0.5)))
    51→          .withMovementPlane(Plane.XY);
    52→
    53→  public static final Distance DEADBAND_IS_AT = Meters.of(0.01);
    54→
    55→  public class setpoints {
    56→    public static final Distance INTAKE_EXTENDED_POSITION = Meters.of(0.26);
    57→    public static final Distance INTAKE_HOMED_POSITION = Meters.of(0.05);
    58→  }
    59→}
