    57→  private final IOperatorController operatorController;
    58→
    59→  private final NamedCommandsRegistery namedCommandsRegistry;
    60→
    61→  private final SwerveDevices simulatedSwerveDevices =
    62→      new SwerveDevices(
    63→          new GyroIO() {},
    64→          new ModuleIOSim(TunerConstants.FrontLeft),
    65→          new ModuleIOSim(TunerConstants.FrontRight),
    66→          new ModuleIOSim(TunerConstants.BackLeft),
    67→          new ModuleIOSim(TunerConstants.BackRight));
    68→
    69→  private final SwerveDevices talonFxSwervedevices =
    70→      new SwerveDevices(
    71→          new GyroIOPigeon2(),
    72→          new ModuleIOTalonFX(TunerConstants.FrontLeft),
    73→          new ModuleIOTalonFX(TunerConstants.FrontRight),
    74→          new ModuleIOTalonFX(TunerConstants.BackLeft),
    75→          new ModuleIOTalonFX(TunerConstants.BackRight));
    76→
    77→  private final SwerveDevices replayedDevices =
    78→      new SwerveDevices(
    79→          new GyroIO() {},
    80→          new ModuleIO() {},
    81→          new ModuleIO() {},
    82→          new ModuleIO() {},
    83→          new ModuleIO() {});
