    87→  public RobotContainer() {
    88→    this.driverController = DriverController.getInstance();
    89→    this.operatorController = OperatorController.getInstance();
    90→
    91→    switch (Constants.getMode()) {
    92→      case REAL:
    93→        drive = new SwerveSubsystem(talonFxSwervedevices);
    94→        break;
    95→
    96→      case SIM:
    97→        drive = new SwerveSubsystem(simulatedSwerveDevices);
    98→        break;
    99→
   100→      default:
   101→        drive = new SwerveSubsystem(replayedDevices);
   102→        break;
   103→    }
   104→
   105→    this.climber = ClimberSubsystem.getInstance();
   106→    this.kicker = KickerSubsystem.getInstance();
   107→    this.turret = TurretSubsystem.getInstance(this.climber.getAbsoluteEncoder());
   108→    this.hood = HoodSubsystem.getInstance();
   109→    this.flyWheel = FlyWheelSubsystem.getInstance();
   110→    this.spindexer = SpindexerSubsystem.getInstance();
   111→    this.roller = RollerSubsystem.getInstance();
   112→    this.extensor = ExtensorSubsystem.getInstance();
   113→
   114→    this.namedCommandsRegistry =
   115→        new NamedCommandsRegistery(drive, roller, extensor, kicker, spindexer, climber);
   116→    this.namedCommandsRegistry.registerAllAutoCommands();
   117→
   118→    this.states =
   119→        new States(
   120→            this.drive,
   121→            this.turret,
   122→            this.hood,
   123→            this.flyWheel,
   124→            this.spindexer,
   125→            this.kicker,
   126→            this.roller,
   127→            this.extensor,
   128→            this.climber);
   129→
   130→    configureButtonBindings();
   131→    configAutoTriggers();
   132→    this.autoChooser = new LoggedDashboardChooser<>("Auto Choices", AutoBuilder.buildAutoChooser());
   133→  }
   134→
   135→  private void configureButtonBindings() {
   136→    this.states.setDefaultStates();
   137→    this.driverController
   138→        .turboActivate()
   139→        .onTrue(this.drive.boostRobotJoystickControlVelocity())
   140→        .onFalse(this.drive.limitRobotJoystickControlVelocity());
   141→
   142→    this.operatorController
   143→        .r2()
   144→        .and(
   145→            () ->
   146→                !RobotStates.getInstance().isOnNonOdometryMode()
   147→                    // && !RobotStates.getInstance().isOnNotShootZone()
   148→                    && this.hood.isAtTargetAngle()
   149→                    && this.turret.isAtTargetAngle()
   150→                    && this.flyWheel.isAtTargetVelocity())
   151→        .whileTrue(
   152→            Commands.parallel(
   153→                this.states.shootState(),
   154→                Commands.runOnce(() -> RobotStates.getInstance().setShootingMode(true))))
   155→        .onFalse(Commands.runOnce(() -> RobotStates.getInstance().setShootingMode(false)));
   156→
   157→    this.operatorController
